#include<bits/stdc++.h>
using namespace std;

char a[1005];

int main()
{
	int len,s=0;  
	fgets(a,1005,stdin);
	len=strlen(a);
	//a[len-1]='\0';
	//len=len-1;
	for(int i=0;i<=len-1;i++)
	{
		if(a[i]!=' ')
		{
			s++;
		}
		else
		{
			if(s>0)
			{
				printf("%d",s);
				printf(",");
				s=0;
		    }
		}
	}
	printf("%d",s);
	return 0;
}
